{"action":"tool_call","tool_name":"write_file","arguments":{"path":"src/template.py","content":"import re
from collections.abc import Mapping
_NAME = re.compile(r'[A-Za-z_][A-Za-z0-9_]*', re.ASCII)
def expand_template(template: str, values) -> str:
    if not isinstance(template, str) or not isinstance(values, Mapping): raise ValueError('invalid inputs')
    replacements = {}
    for name, value in values.items():
        if not isinstance(name, str) or _NAME.fullmatch(name) is None or not isinstance(value, str) or name in replacements: raise ValueError('invalid mapping')
        replacements[name] = value
    result = []; index = 0
    while index < len(template):
        if template[index] != '$': result.append(template[index]); index += 1; continue
        if index + 1 >= len(template): raise ValueError('lone dollar')
        if template[index + 1] == '$': result.append('$'); index += 2; continue
        if template[index + 1] != '{': raise ValueError('malformed dollar')
        end = template.find('}', index + 2)
        if end < 0: raise ValueError('unclosed placeholder')
        name = template[index + 2:end]
        if _NAME.fullmatch(name) is None or name not in replacements: raise ValueError('invalid placeholder')
        result.append(replacements[name]); index = end + 1
    return ''.join(result)
